import {
    KeypairSigner,
    PublicKey,
    RpcSendTransactionOptions,
    Transaction,
    TransactionBuilderSendAndConfirmOptions,
    createSignerFromKeypair,
} from '@metaplex-foundation/umi'
import { createWeb3JsEddsa } from '@metaplex-foundation/umi-eddsa-web3js'
import { Connection } from '@solana/web3.js'
import * as bip39 from 'bip39'
import { derivePath } from 'ed25519-hd-key'

import {
    Provider,
    SignedTransaction,
    Signer,
    TransactionPending,
    TransactionReceipt,
    TransactionRequest,
} from '@layerzerolabs/lz-core'

import { SolanaProvider } from '../providers'

/**
 * Represents a Solana blockchain signer.
 * Implements the Signer interface for interacting with Solana-compatible blockchains.
 */
export class SolanaSigner implements Signer {
    private readonly keypair: KeypairSigner
    private provider?: SolanaProvider

    /**
     * Creates an instance of SolanaSigner.
     *
     * @param {KeypairSigner} keypair - The Solana keypair to use as the signer.
     */
    private constructor(keypair: KeypairSigner) {
        this.keypair = keypair
    }

    /**
     * Creates an instance of SolanaSigner from a KeypairSigner.
     *
     * @param {KeypairSigner} source - The Solana keypair to create the signer from.
     * @returns {SolanaSigner} The created SolanaSigner instance.
     */
    static from(source: KeypairSigner): SolanaSigner

    /**
     * Creates an instance of SolanaSigner from a mnemonic and derivation path.
     *
     * @param {string} mnemonic - The mnemonic to create the signer from.
     * @param {string} path - The derivation path (e.g., m/44'/501'/0'/0').
     * @returns {SolanaSigner} The created SolanaSigner instance.
     */
    static from(mnemonic: string, path: string): SolanaSigner

    /**
     * Creates an instance of SolanaSigner from the given source.
     *
     * @param {KeypairSigner | string} source - The source to create the signer from.
     * @param {string} [path] - The derivation path (optional).
     * @returns {SolanaSigner} The created SolanaSigner instance.
     * @throws {Error} If the parameters are invalid.
     */
    static from(source: KeypairSigner | string, path?: string): SolanaSigner {
        if (typeof source === 'object') {
            return new this(source)
        } else if (typeof source === 'string') {
            const keypair = getKeypair(source, path)
            return new this(keypair)
        } else {
            throw new Error('Invalid parameters')
        }
    }

    /**
     * Gets the native Solana keypair instance.
     *
     * @returns {KeypairSigner} The native Solana keypair instance.
     */
    get native(): KeypairSigner {
        return this.keypair
    }

    /**
     * Connects the signer to a provider.
     *
     * @param {Provider | Connection} provider - The provider to connect to.
     * @returns {this} The connected signer.
     * @throws {Error} If the provider is not an instance of Connection.
     */
    connect(provider: Connection | Provider): this {
        if (provider instanceof Connection) {
            this.provider = SolanaProvider.from(provider)
        } else if (provider instanceof SolanaProvider) {
            this.provider = provider
        } else {
            throw new Error('Invalid parameters')
        }
        return this
    }

    /**
     * Gets the address of the signer.
     *
     * @returns {Promise<string>} A promise that resolves to the address of the signer.
     */
    async getAddress(): Promise<string> {
        return Promise.resolve(this.keypair.publicKey)
    }

    /**
     * Gets the address of the signer.
     *
     * @returns {string} The address of the signer.
     */
    get address(): string {
        return this.publicKey
    }

    /**
     * Gets the public key of the signer.
     *
     * @returns {PublicKey} The public key of the signer.
     */
    get publicKey(): PublicKey {
        return this.keypair.publicKey
    }

    /**
     * Gets the secret key of the signer.
     *
     * @returns {Uint8Array} The secret key of the signer.
     */
    get secretKey(): Uint8Array {
        return this.keypair.secretKey
    }

    /**
     * Sends a signed transaction and waits for confirmation.
     *
     * @param {SignedTransaction} transaction - The signed transaction to send.
     * @param {TransactionBuilderSendAndConfirmOptions} [opts] - Optional parameters for sending and confirming the transaction.
     * @returns {Promise<TransactionReceipt>} A promise that resolves to the transaction receipt.
     */
    async sendAndConfirm(
        transaction: SignedTransaction,
        opts?: TransactionBuilderSendAndConfirmOptions
    ): Promise<TransactionReceipt> {
        const provider = this.assertAndGetProvider()
        return provider.sendAndConfirm(transaction, opts)
    }

    /**
     * Sends a signed transaction.
     *
     * @param {SignedTransaction} transaction - The signed transaction to send.
     * @param {RpcSendTransactionOptions} [opts] - Optional parameters for sending the transaction.
     * @returns {Promise<TransactionPending>} A promise that resolves to the pending transaction.
     */
    async sendTransaction(
        transaction: SignedTransaction,
        opts?: RpcSendTransactionOptions
    ): Promise<TransactionPending> {
        const provider = this.assertAndGetProvider()
        return provider.sendTransaction(transaction, opts)
    }

    /**
     * Signs a transaction.
     *
     * @param {TransactionRequest} transaction - The transaction request to sign.
     * @param {Commitment | GetLatestBlockhashConfig} [opts] - Optional parameters for signing the transaction.
     * @returns {Promise<SignedTransaction>} A promise that resolves to the signed transaction.
     */
    async signTransaction(transaction: TransactionRequest): Promise<SignedTransaction> {
        const tx = transaction.request as Transaction
        const signedTransaction: Transaction = await this.keypair.signTransaction(tx)
        return SignedTransaction.from(signedTransaction)
    }

    /**
     * Signs a buffer (e.g., a message hash) using the native Solana signer.
     *
     * @param {Uint8Array} _buffer - The buffer to sign.
     * @returns {Promise<Uint8Array>} A promise that resolves to the signed buffer as a Uint8Array.
     * @throws {Error} Method not implemented.
     */
    async signBuffer(_buffer: Uint8Array): Promise<Uint8Array> {
        await Promise.resolve()
        throw new Error('Method not implemented.')
    }

    private assertAndGetProvider(): SolanaProvider {
        if (!this.provider) {
            throw new Error('Signer was not connected to a provider, did you forgot to connect to provider?')
        }
        return this.provider
    }
}

/**
 * Generates a Keypair from a mnemonic and derivation path.
 *
 * @param {string} mnemonic - The mnemonic to generate the keypair from.
 * @param {string} [path="m/44'/501'/0'/0'"] - The derivation path (optional).
 * @returns {KeypairSigner} The generated Keypair.
 */
function getKeypair(mnemonic: string, path = "m/44'/501'/0'/0'"): KeypairSigner {
    const eddsa = createWeb3JsEddsa()

    const seed = bip39.mnemonicToSeedSync(mnemonic, '') // (mnemonic, password)
    const privateKey = derivePath(path, seed.toString('hex')).key
    return createSignerFromKeypair({ eddsa }, eddsa.createKeypairFromSeed(privateKey))
}

